<?php
 namespace WPAICG\Core\Stream\Formatter; if (!defined('ABSPATH')) { exit; } function get_sse_runtime_capabilities_logic(): array { return [ 'session_active' => session_status() === PHP_SESSION_ACTIVE, 'apache_setenv_available' => function_exists('apache_setenv'), 'implicit_flush_available' => function_exists('ob_implicit_flush'), 'fastcgi_finish_available' => function_exists('fastcgi_finish_request'), 'litespeed_finish_available' => function_exists('litespeed_finish_request'), 'output_buffer_level' => ob_get_level(), ]; } function apply_sse_runtime_mitigations_logic(): void { $capabilities = get_sse_runtime_capabilities_logic(); ignore_user_abort(true); if ($capabilities['session_active']) { session_write_close(); } if ($capabilities['apache_setenv_available']) { @apache_setenv('no-gzip', '1'); @apache_setenv('dont-vary', '1'); } if ($capabilities['implicit_flush_available']) { @ob_implicit_flush(true); } while (ob_get_level() > 0) { ob_end_clean(); } } function send_sse_response_headers_logic(): void { header('Cache-Control: no-cache, no-store, must-revalidate, max-age=0, no-transform'); header('Pragma: no-cache'); header('Content-Type: text/event-stream; charset=utf-8'); header('X-Accel-Buffering: no'); header('Connection: keep-alive'); set_time_limit(0); } function send_sse_preamble_logic(\WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance): void { if ($formatterInstance->get_preamble_sent_status()) { return; } send_raw_logic(':' . str_repeat(' ', 4096) . "\n\n"); $formatterInstance->set_preamble_sent_status(true); } function finish_sse_request_logic(): void { $capabilities = get_sse_runtime_capabilities_logic(); if ($capabilities['fastcgi_finish_available']) { fastcgi_finish_request(); return; } if ($capabilities['litespeed_finish_available']) { litespeed_finish_request(); } } function set_sse_headers_logic(\WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance): void { if ($formatterInstance->get_headers_sent_status() || headers_sent()) { return; } apply_sse_runtime_mitigations_logic(); send_sse_response_headers_logic(); $formatterInstance->set_headers_sent_status(true); send_sse_preamble_logic($formatterInstance); } function send_sse_data_logic(\WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance, $data, ?string $id = null): void { $json_data = is_string($data) ? $data : json_encode($data, JSON_UNESCAPED_UNICODE); $output = ''; if ($id !== null) { $output .= "id: {$id}\n"; } $output .= "data: {$json_data}\n\n"; $formatterInstance->send_raw_public_wrapper($output); } function send_sse_event_logic(\WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance, string $event_type, $data, ?string $id = null): void { $json_data = is_string($data) ? $data : json_encode($data, JSON_UNESCAPED_UNICODE); $output = "event: {$event_type}\n"; if ($id !== null) { $output .= "id: {$id}\n"; } $output .= "data: {$json_data}\n\n"; $formatterInstance->send_raw_public_wrapper($output); } function send_sse_error_logic( \WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance, string $message, bool $non_fatal = false, array $extra_data = [] ): void { $event_type = $non_fatal ? 'warning' : 'error'; $error_data = array_merge(['error' => $message], $extra_data); $error_id = 'err-' . time(); $formatterInstance->send_sse_event($event_type, $error_data, $error_id); } function send_sse_done_logic(\WPAICG\Core\Stream\Formatter\SSEResponseFormatter $formatterInstance): void { $formatterInstance->send_sse_event('done', ['finished' => true]); } function send_raw_logic(string $output): void { if (connection_status() === CONNECTION_NORMAL) { echo $output; if (ob_get_level() > 0) { @ob_flush(); } @flush(); } } 